+mod tests {
+    use super::*;
+
+    // ================================================================
+    // SseEvent serialization
+    // ================================================================
+
+    #[test]
+    fn event_data_only() {
+        let event = SseEvent::default().data("hello");
+        assert_eq!(event.to_string(), "data:hello\n\n");
+    }
+
+    #[test]
+    fn event_with_type() {
