+        assert_eq!(event.to_string(), "event:message\ndata:hello\n\n");
+    }
+
+    #[test]
+    fn event_with_id() {
+        let event = SseEvent::default().data("hello").id("42");
+        assert_eq!(event.to_string(), "data:hello\nid:42\n\n");
+    }
+
+    #[test]
+    fn event_with_retry() {
